# WRONG: use the token, catch the 401, then decide what to do
def call_api(url, token):
    resp = httpx.get(url, headers={"Authorization": f"Bearer {token}"})
    if resp.status_code == 401:
        # Too late -- call already failed; fallback may escalate to admin token
        token = get_fresh_token()  # BUG: may return a broader token
        resp = httpx.get(url, headers={"Authorization": f"Bearer {token}"})
    return resp


# RIGHT: check expiry proactively with a safety margin
def call_api(url, token_obj: OAuthToken):
    if token_obj.is_expired:  # checks time.time() > expires_at - 30
        token_obj = fetch_token_with_same_scope()  # same scope, NOT broader
    return httpx.get(
        url,
        headers={"Authorization": f"Bearer {token_obj.access_token}"},
    )
